        <pre style="margin: 0; font-family: 'Fira Code', monospace; font-size: 13px; color: #795548;">try:
    with open("log.txt", "a") as f:
        f.write("Nobita borrowed Anywhere Door\n")
except IOError:
    print("Failed to write access log to disk!")</pre>
